Here's an example code for a Discord bot using Discord.js v14 with a single slash command named "ban":

```javascript
const { Client, Intents, Permissions, SlashCommandBuilder } = require('discord.js');
const client = new Client({ intents: [Intents.FLAGS.GUILDS, Intents.FLAGS.GUILD_MESSAGES] });

client.once('ready', () => {
  console.log('Bot is online!');
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const { commandName, options } = interaction;

  if (commandName === 'ban') {
    const user = options.getUser('target');
    const member = interaction.guild.members.cache.get(user.id);

    if (!interaction.member.permissions.has(Permissions.FLAGS.BAN_MEMBERS)) {
      return interaction.reply('You don\'t have permission to ban members.');
    }

    if (!member.permissions.has(Permissions.FLAGS.BAN_MEMBERS)) {
      return interaction.reply('The user you are trying to ban does not have the permission to be banned.');
    }

    try {
      await member.ban();
      await interaction.reply(`Successfully banned ${user.tag}`);
    } catch (error) {
      console.error(error);
      await interaction.reply('An error occurred while trying to ban the user.');
    }
  }
});

const commands = [
  new SlashCommandBuilder()
    .setName('ban')
    .setDescription('Ban a user from the server')
    .addUserOption(option =>
      option.setName('target')
        .setDescription('The user to ban')
        .setRequired(true)
    )
];

client.once('ready', () => {
  client.application.commands.set(commands);
  console.log('Commands registered!');
});

client.login('YOUR_BOT_TOKEN');
```

Replace `'YOUR_BOT_TOKEN'` with your bot's token. This code registers the `ban` command with Discord and handles the interaction logic in the `interactionCreate` event. It also includes permission checks to make sure the user executing the command has the necessary permissions to ban members.

