#include <string>

std::string markdownToHtml(const std::string& markdown) {
    std::string html = markdown;

    // Replace markdown headers with html headers
    size_t pos = 0;
    while ((pos = html.find("# ", pos)) != std::string::npos) {
        std::string headerText = html.substr(pos + 2, html.find(" ", pos + 2) - (pos + 2));
        html.replace(pos, html.find(" ", pos + 2), "<h1>" + headerText + "</h1>");
        pos += "<h1>" + headerText + "</h1>".length();
    }

    // Replace markdown bold with html bold
    pos = 0;
    while ((pos = html.find("**", pos)) != std::string::npos) {
        std::string boldText = html.substr(pos + 2, html.find("*", pos + 2) - (pos + 2));
        html.replace(pos, html.find("*", pos + 2), "<strong>" + boldText + "</strong>");
        pos += "<strong>" + boldText + "</strong>".length();
    }

    // Replace markdown italic with html italic
    pos = 0;
    while ((pos = html.find("*", pos)) != std::string::npos) {
        std::string italicText = html.substr(pos + 1, html.find("*", pos + 1) - (pos + 1));
        html.replace(pos, html.find("*", pos + 1), "<em>" + italicText + "</em>");
        pos += "<em>" + italicText + "</em>".length();
    }

    // Replace markdown links with html links
    pos = 0;
    while ((pos = html.find("[](", pos)) != std::string::npos) {
        std::string linkText = html.substr(pos + 3, html.find(")", pos + 3) - (pos + 3));
        std::string linkUrl = html.substr(html.find("(", pos + 3) + 1, html.find(")", pos + 3) - (html.find("(", pos + 3) + 1));
        html.replace(pos, "<a href=\"" + linkUrl + "\">" + linkText + "</a>".length(), "<a href=\"" + linkUrl + "\">" + linkText + "</a>");
        pos += "<a href=\"" + linkUrl + "\">" + linkText + "</a>".length();
    }

    return html;
}
```

This function uses a series of string replace calls to convert markdown formatting to HTML formatting. It handles headers, bold and italic text, and links. Note that this implementation is oversimplified and doesn't handle all possible markdown syntaxes and edge cases.

