Here's a function in JavaScript that takes an array of 5 numbers as input and checks if any of the numbers is a valid prime number. If a prime number is found, it will print the number to the console:

```javascript
function checkPrimeNumbers(numbers) {
  for (let i = 0; i < numbers.length; i++) {
    if (isPrime(numbers[i])) {
      console.log(numbers[i]);
    }
  }
}

function isPrime(number) {
  if (number <= 1) {
    return false;
  }
  for (let i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) {
      return false;
    }
  }
  return true;
}

// Example usage:
